import Foundation

let questions8: [QuizQuestion] = [
QuizQuestion(id:531,question:"O que Paulo ensina sobre a esperança em Romanos 5:1-5?",options:["A esperança é incerta","Esperança vem da riqueza","Esperança é apenas para o futuro","Justificados pela fé"],correctIndex:3,explanation:"Rm 5:1-5: a cadeia justificação→paz→tribulação→perseverança→caráter→esperança, fundada no amor de Deus derramado pelo Espírito — esperança que não decepciona.",reference:"Romanos 5:1-5",category:.geral,propheticMeaning:"O Espírito Santo garantindo a esperança (v.5) é o adiantamento do que virá — 'as arras do Espírito' (2 Co 1:22) como garantia antecipada da herança prometida."),
QuizQuestion(id:532,question:"Quem são 'os pobres em espírito' de Mateus 5:3?",options:["Os que reconhecem sua pobreza","Os economicamente pobres apenas","Os humilhados pelos outros","Os que praticam ascetismo"],correctIndex:0,explanation:"'Pobres em espírito' reconhecem sua bancarrota espiritual — o oposto do orgulho farisaico. São a condição básica para receber o Reino.",reference:"Mateus 5:3",category:.geral,propheticMeaning:"A primeira bem-aventurança define o perfil do discípulo: espiritualmente em débito (ptōchos = mendigo), completamente dependente de Deus. É a antítese do autossuficiente e o estado de todo crente genuíno."),
QuizQuestion(id:533,question:"O que é a 'comunhão com o sofrimento de Cristo' em Filipenses 3:10?",options:["Sofrer doenças como expiação","O objetivo de Paulo: conhecer Cristo","Penitências religiosas","Um estado espiritual avançado apenas para..."],correctIndex:1,explanation:"Fp 3:10-11: Paulo deseja conhecer Cristo 'na participação dos seus sofrimentos, tornando-me conformado à sua morte' — o caminho para a ressurreição passa pela cruz.",reference:"Filipenses 3:10-11",category:.geral,propheticMeaning:"'Conformado à sua morte' (symmorphizomenos) — o crente não apenas aceita o sofrimento passivamente, mas é ativamente moldado pela cruz no próprio caráter, compartilhando o modo de existir cruciforme de Cristo."),
QuizQuestion(id:534,question:"O que Paulo ensina sobre a gratidão em Colossenses 3:17?",options:["Agradeça apenas quando as coisas vão bem","A gratidão é apenas para pastores","'Tudo o que fizerdes","Agradeça somente na oração"],correctIndex:2,explanation:"Cl 3:17: toda a vida — palavras e ações — deve ser feita em nome de Jesus com gratidão constante ao Pai. A gratidão permeia toda a existência cristã.",reference:"Colossenses 3:17",category:.geral,propheticMeaning:"'Tudo em nome do Senhor Jesus' santifica o ordinário — comer, trabalhar, descansar tornam-se atos de adoração quando feitos na consciência da presença e autoridade de Cristo."),
QuizQuestion(id:535,question:"O que Paulo diz sobre ser 'mais que vencedor' em Romanos 8:37?",options:["Que crentes sempre vencem circunstâncias","Que o sofrimento nunca ocorre","Que vitória significa prosperidade","'Em todas estas coisas somos mais que..."],correctIndex:3,explanation:"Rm 8:37: 'hypernikōmen' (super-vitória) — não vitória sobre o sofrimento mas no sofrimento, pelo amor de Cristo que nem morte nem perseguição podem separar-nos.",reference:"Romanos 8:37",category:.geral,propheticMeaning:"A vitória cristã não é escapar do sofrimento mas triumphar através dele — como Cristo que 'venceu pelo sangue do Cordeiro' (Ap 12:11). O sofrimento não contradiz a vitória; é o meio dela."),
QuizQuestion(id:536,question:"O que Paulo ensina sobre a fidelidade de Deus em 2 Timóteo 2:13?",options:["'Se somos infiéis, ele permanece fiel","Se somos infiéis Deus pode falhar","A salvação pode ser perdida pela...","Deus abandona os infiéis"],correctIndex:0,explanation:"2 Tm 2:13: mesmo quando somos infiéis, Deus permanece fiel — sua fidelidade não é condicional à nossa, porque é parte de sua natureza imutável.",reference:"2 Timóteo 2:13",category:.geral,propheticMeaning:"A fidelidade incondicional de Deus é o fundamento da segurança da salvação — nossa salvação não depende de nossa fidelidade (que oscila) mas da fidelidade de Cristo que 'não pode negar-se a si mesmo.'"),
QuizQuestion(id:537,question:"O que Hebreus 4:12 diz sobre a Palavra de Deus?",options:["A Palavra é apenas história","'A Palavra de Deus é viva e eficaz","A Palavra é apenas simbólica","A Palavra é menos importante que..."],correctIndex:1,explanation:"Hb 4:12: a Palavra de Deus tem vida própria (viva), eficácia (ativa), penetração (espada) e discernimento (revelando os pensamentos e intenções do coração).",reference:"Hebreus 4:12",category:.geral,propheticMeaning:"A Palavra 'viva e eficaz' é agente do Espírito Santo — não apenas informação mas transformação. Quando pregada e lida com fé, opera naquele que a recebe mais do que qualquer palavra humana."),
QuizQuestion(id:538,question:"O que Paulo ensina sobre a liberdade cristã em Gálatas 5:1?",options:["Liberdade para fazer qualquer coisa","Liberdade para ignorar a ética","'Cristo nos libertou para a liberdade.","Liberdade apenas espiritual sem"],correctIndex:2,explanation:"Gl 5:1: a liberdade cristã é libertação do jugo da lei como sistema de salvação — não para pecar (Rm 6:1-2) mas para amar (Gl 5:13-14).",reference:"Gálatas 5:1",category:.geral,propheticMeaning:"'Libertos para o amor' — a lei exige, o amor realiza. O que a lei ordenava externamente, o amor faz internamente. A liberdade cristã é a capacidade de cumprir pelo amor o que a lei nunca pôde exigir."),
QuizQuestion(id:539,question:"O que é o 'sacrifício vivo' em Romanos 12:1?",options:["Oferecer animais","Um rito especial","Apenas a oração","Apresentar o corpo"],correctIndex:3,explanation:"Rm 12:1: Paulo apela pela misericórdias divinas a apresentar o corpo como sacrifício vivo — a adoração cristã não é ritual do templo mas vida entregue.",reference:"Romanos 12:1",category:.geral,propheticMeaning:"O sacrifício vivo contrasta com o sacrifício morto do AT — não animais mortos mas vidas entregues. Cristo ofereceu-se como sacrifício vivo (Jo 10:17-18); o crente é chamado a participar do mesmo modo de vida."),
QuizQuestion(id:540,question:"O que Paulo ensina sobre a mente de Cristo em 1 Coríntios 2:16?",options:["'Nós temos a mente de Cristo'","Apenas apóstolos têm a mente de Cristo","A mente de Cristo é inatingível","Apenas através de estudos avançados"],correctIndex:0,explanation:"1 Co 2:14-16: o 'homem espiritual' discerne tudo espiritualmente e tem 'a mente de Cristo' — capacidade dada pelo Espírito de compreender as coisas de Deus.",reference:"1 Coríntios 2:14-16",category:.geral,propheticMeaning:"'A mente de Cristo' é dom do Espírito que transforma a maneira de ver toda a realidade — o crente passa a ver as coisas do ponto de vista de Deus, não apenas do ponto de vista humano."),
QuizQuestion(id:541,question:"O que significa 'teologia natural' segundo Romanos 1:20?",options:["A natureza ensina tudo sobre Deus","'As perfeições invisíveis de Deus... o...","A natureza contradiz a Bíblia","Apenas cristãos podem conhecer Deus pela..."],correctIndex:1,explanation:"Rm 1:20: a criação revela o eterno poder e divindade de Deus — suficiente para responsabilizar todos, mas insuficiente para salvar. A revelação especial (evangelho) é necessária para a salvação.",reference:"Romanos 1:20",category:.geral,propheticMeaning:"A revelação natural faz todos responsáveis; a revelação especial (Cristo e as Escrituras) faz todos convidados. O universo aponta para o Criador; o evangelho revela o Redentor."),
QuizQuestion(id:542,question:"O que Paulo diz sobre a homossexualidade em Romanos 1:26-27?",options:["A Bíblia não menciona o tema","Apenas uma questão cultural do 1º século","Paulo menciona relações entre...","É neutro na Bíblia"],correctIndex:2,explanation:"Rm 1:24-27: a idolatria (troca de Deus pela criação) resulta em outras inversões, incluindo trocas de relações naturais por não naturais — parte do argumento sobre a queda universal.",reference:"Romanos 1:26-27",category:.geral,propheticMeaning:"Paulo não está selecionando pecados: o argumento de Rm 1-3 é que toda a humanidade, judeus e gentios, está igualmente sob o juízo de Deus e igualmente necessita do evangelho (Rm 3:23)."),
QuizQuestion(id:543,question:"O que Pedro ensina sobre o batismo em 1 Pedro 3:21?",options:["Batismo salva automaticamente","Batismo é apenas símbolo sem importância","Batismo infantil é proibido","'O batismo agora vos salva (não pela..."],correctIndex:3,explanation:"1 Pe 3:21: o batismo salva não pelo ato externo (água) mas pelo que representa — o apelo da fé a Deus, fundamentado na ressurreição de Cristo.",reference:"1 Pedro 3:21",category:.geral,propheticMeaning:"O batismo ligado à ressurreição de Cristo (v.21) confirma o significado paulino de Rm 6:3-4 — o batismo proclama morte e ressurreição com Cristo, unindo o crente ao fundamento de toda salvação."),
QuizQuestion(id:544,question:"O que Jesus ensina sobre a ovelha perdida em Lucas 15:3-7?",options:["O pastor deixa as 99 e busca a perdida","Que não vale recuperar uma ovelha perdida","Que a maioria é mais importante","Que os pecadores são descartáveis"],correctIndex:0,explanation:"Lucas 15:3-7: Deus como pastor que busca ativamente a ovelha perdida e celebra quando a encontra — imagem do coração de Deus para com os pecadores.",reference:"Lucas 15:3-7",category:.geral,propheticMeaning:"As três parábolas de Lucas 15 (ovelha perdida, moeda perdida, filho perdido) revelam um Deus que busca, não que espera passivamente — o evangelho é a busca ativa de Deus pela criação perdida."),
QuizQuestion(id:545,question:"O que é a parábola da moeda perdida (Lucas 15:8-10)?",options:["Sobre economia doméstica","A mulher que perde uma moeda acende a","Sobre a importância de economizar","Sobre encontrar objetos perdidos"],correctIndex:1,explanation:"Lucas 15:8-10: a mulher que busca persistentemente a moeda perdida é imagem de Deus que busca diligentemente o pecador perdido — e há alegria diante dos anjos ao encontrá-lo.",reference:"Lucas 15:8-10",category:.geral,propheticMeaning:"A luz acesa, a casa varrida — Deus poupa nenhum esforço para encontrar o que é seu. O Espírito Santo é essa luz que ilumina o interior do coração humano em busca do perdido."),
QuizQuestion(id:546,question:"O que é a cura do cego Bartimeu?",options:["Um símbolo apenas","Uma parábola sobre visão espiritual","Jesus curou Bartimeu (cego mendigo de...","A cura de um samaritano"],correctIndex:2,explanation:"Marcos 10:46-52: Bartimeu clamou insistentemente pelo 'Filho de Davi' (título messiânico), Jesus o chamou e perguntou o que queria. Pela fé foi curado e seguiu Jesus.",reference:"Marcos 10:46-52",category:.geral,propheticMeaning:"'O que queres que te faça?' — Jesus que conhece tudo nos convida a articular nosso desejo. A oração específica honra a Deus e exercita a fé. Bartimeu abandonou o manto (sua única propriedade) para correr a Jesus."),
QuizQuestion(id:547,question:"O que é a conversão de Zaqueu (Lucas 19)?",options:["Uma parábola","Um milagre de cura","Uma parábola sobre riqueza","Zaqueu, cobrador de impostos"],correctIndex:3,explanation:"Lucas 19:1-10: a conversão de Zaqueu resultou em restituição (fruto de arrependimento genuíno) e Jesus declarou 'hoje veio a salvação a esta casa.' Culmina em: 'O Filho do Homem veio buscar e salvar o perdido.'",reference:"Lucas 19:1-10",category:.geral,propheticMeaning:"Zaqueu restituindo quatro vezes o que roubou demonstra que arrependimento bíblico tem implicações materiais e relacionais — não apenas sentimento interior mas mudança de comportamento e restituição."),
QuizQuestion(id:548,question:"O que Jesus ensinou sobre a ressurreição aos saduceus (Mateus 22)?",options:["'Não conheceis as Escrituras nem o poder","Que a ressurreição não existe","Que há casamento na ressurreição","Que a ressurreição é apenas espiritual"],correctIndex:0,explanation:"Mt 22:23-32: os saduceus questionaram Jesus sobre a ressurreição com um dilema artificial. Jesus respondeu que na ressurreição não há casamento, e Deus se revelou como 'Deus de Abraão' no presente — provando que eles vivem.",reference:"Mateus 22:29-32",category:.geral,propheticMeaning:"'Deus não é Deus de mortos mas de vivos' — a fórmula divina 'Eu sou o Deus de Abraão' (tempo presente) implica que Abraão ainda existe. Até o AT afirma a ressurreição para quem lê corretamente."),
QuizQuestion(id:549,question:"O que Jesus ensinou sobre o maior mandamento segundo os escribas?",options:["Guardar o sábado","Amar a Deus de todo","Ser circuncidado","Oferecer sacrifícios"],correctIndex:1,explanation:"Marcos 12:28-34: o escriba que perguntou ficou satisfeito com a resposta de Jesus e concordou. Jesus disse que ele não estava longe do reino de Deus.",reference:"Marcos 12:28-34",category:.geral,propheticMeaning:"O escriba que entendeu que amar a Deus e ao próximo 'vale mais do que todos os holocaustos e sacrifícios' chegou perto do coração do evangelho — a graça que produz amor é mais do que religião."),
QuizQuestion(id:550,question:"O que Jesus ensina sobre o Filho de Davi (Mateus 22:41-46)?",options:["Que o Messias é apenas humano","Que Davi era superior ao Messias","Usando o Salmo 110:1","Que o Messias não é filho de Davi"],correctIndex:2,explanation:"Mt 22:41-46: Jesus usou o Salmo 110 para revelar que o Messias (Filho de Davi) é também o Senhor de Davi — transcendendo a expectativa meramente política e humana.",reference:"Mateus 22:41-46; Salmos 110:1",category:.geral,propheticMeaning:"Jesus revelando que o Messias é simultaneamente filho e Senhor de Davi aponta para a dupla natureza: totalmente humano (filho de Davi) e totalmente divino (Senhor de Davi). Nenhum rabino conseguiu responder."),
QuizQuestion(id:551,question:"Quais são os sinais da segunda vinda em Mateus 24?",options:["Nenhum sinal será dado","Apenas sinais celestiais","A segunda vinda será sem sinais","Falsos cristos, guerras, fomes"],correctIndex:3,explanation:"Mt 24:4-14: Jesus listou sinais progressivos culminando na pregação do evangelho 'a todas as nações' como precursor do fim.",reference:"Mateus 24:4-14",category:.geral,propheticMeaning:"'Este evangelho do reino será pregado em todo o mundo... e então virá o fim' (Mt 24:14) — a missão mundial da Igreja está conectada à consumação escatológica. A evangelização é urgência escatológica."),
QuizQuestion(id:552,question:"O que é o 'abominação da desolação' mencionada por Jesus?",options:["A profecia de Daniel 9:27 citada por","A destruição do templo por Herodes","O pecado de Adão","A construção da Torre de Babel"],correctIndex:0,explanation:"Mt 24:15 cita Daniel 9:27 — 'a abominação da desolação no lugar santo.' Historicamente ocorreu com Antíoco IV (167 a.C.); Jesus previu uma repetição relacionada à destruição do templo em 70 d.C.",reference:"Mateus 24:15; Daniel 9:27",category:.geral,propheticMeaning:"A 'abominação da desolação' aponta para a profanação do lugar de adoração por sistemas antijristicos — cumprida em 70 d.C. e apontando para cumprimento escatológico final (2 Ts 2:4)."),
QuizQuestion(id:553,question:"O que Jesus comparou à sua segunda vinda em Mateus 24:27?",options:["Uma nuvem que cresce devagar","'Assim como o relâmpago sai do","Uma névoa discreta","Uma transformação gradual"],correctIndex:1,explanation:"Mt 24:27: a segunda vinda será tão visível quanto um relâmpago no horizonte — impossível de ser confundida ou perdida. Isso contrasta com os 'falsos cristos' que aparecem 'no deserto' ou 'nas câmaras' (v.26).",reference:"Mateus 24:27",category:.geral,propheticMeaning:"A visibilidade do relâmpago protege contra a decepção de 'falsos cristos' — qualquer 'segunda vinda' que não seja universalmente visível e gloriosa não é o Cristo bíblico."),
QuizQuestion(id:554,question:"O que é a 'Ceia do Senhor' como refeição escatológica?",options:["Apenas um memorial do passado","Uma refeição apenas simbólica","A Ceia proclama a morte de Cristo","Apenas para o presente"],correctIndex:2,explanation:"1 Co 11:26: a Ceia tem dimensão tríplice — passado (morte de Cristo), presente (comunhão) e futuro ('até que ele venha'). É um sacramento escatológico.",reference:"1 Coríntios 11:26",category:.geral,propheticMeaning:"A Ceia antecipando o banquete do reino conecta cada participação à esperança escatológica — cada vez que a Igreja come e bebe, ela proclama e ansia pela consumação do casamento do Cordeiro (Ap 19:9)."),
QuizQuestion(id:555,question:"O que é a 'pedra rejeitada' em Salmo 118:22 e seu cumprimento?",options:["Uma pedra do templo","Uma profecia sobre Salomão","Uma metáfora sem cumprimento","'A pedra que os edificadores"],correctIndex:3,explanation:"Salmo 118:22 profetizou a rejeição do Messias pelos líderes de Israel. Jesus citou este versículo para si mesmo após a parábola dos lavradores (Mt 21:42).",reference:"Salmos 118:22; Mateus 21:42; 1 Pedro 2:7",category:.profetas,propheticMeaning:"O 'rejeitado' se tornando 'pedra angular' é o padrão paradoxal do Reino: o crucificado tornou-se o fundamento da Igreja. 'Esta é obra do Senhor e é maravilhosa aos nossos olhos' (Sl 118:23)."),
QuizQuestion(id:556,question:"Qual é a profecia de Isaías 49:6 sobre a missão do Servo?",options:["'Ainda é pouco seres meu Servo para...","O Servo governará apenas Israel","O Servo viria apenas para judeus","O Servo seria sacerdote"],correctIndex:0,explanation:"Isaías 49:6: o mandato do Servo se expande de Israel para as nações — cumprido explicitamente na missão de Paulo (At 13:47) e na Grande Comissão.",reference:"Isaías 49:6; Atos 13:47",category:.profetas,propheticMeaning:"Paulo citou Isaías 49:6 ao se voltar para os gentios (At 13:47) — confirmando que a missão universal da Igreja é o cumprimento do mandato dado ao Servo-Messias no AT."),
QuizQuestion(id:557,question:"Qual é o tema do livro de Rute em relação à redenção?",options:["A história de emigração de Midiã","Boaz como go'el (parente redentor)","Uma história de romance apenas","O regresso de Israel do exílio"],correctIndex:1,explanation:"Rute: o go'el tinha direito, capacidade e disposição para resgatar. Boaz redimiu Rute (uma moabita estrangeira) — tipo de Cristo que redime os gentios da pobreza espiritual.",reference:"Rute 4:9-10; Gálatas 3:13",category:.profetas,propheticMeaning:"Boaz indo além da lei para mostrar 'bondade maior' (Rt 3:10) a Rute prefigura Cristo indo além do que a lei exigia para nos resgatar — 'gracia sobre graça' (Jo 1:16), não apenas dever mas amor."),
QuizQuestion(id:558,question:"O que o livro de Jó ensina sobre o sofrimento?",options:["Sofrimento é sempre punição","Deus nunca permite sofrimento aos justos","O justo pode sofrer sem que haja pecado","O sofrimento é ilusório"],correctIndex:2,explanation:"Jó mostra que sofrimento não é automaticamente punição — Jó era 'íntegro e reto, temente a Deus' e mesmo assim sofreu. A resposta final de Deus do redemoinho não explica tudo mas revela Deus.",reference:"Jó 1:1; 42:5",category:.profetas,propheticMeaning:"Jó 42:5: 'Outrora ouvia falar de ti, mas agora os meus olhos te veem.' O sofrimento levou Jó da religião de segunda mão (ouvi) para o encontro pessoal (vi) — a dor pode ser o portal para a visão mais profunda de Deus."),
QuizQuestion(id:559,question:"Qual é a promessa central do livro de Rute 1:16?",options:["Que Rute voltaria a Moabe","Uma promessa sobre terras","Uma promessa sobre filhos","'Onde tu morreres, morrerei eu"],correctIndex:3,explanation:"Rute 1:16-17: a declaração de lealdade de Rute é um dos mais belos textos de amor e fidelidade da Bíblia — ela escolheu o povo e o Deus de Noemi acima de sua própria família e terra.",reference:"Rute 1:16-17",category:.profetas,propheticMeaning:"'Teu povo será o meu povo e teu Deus será o meu Deus' — Rute ilustra a entrada dos gentios no povo de Deus pela fé, anticipando que a promessa de Abraão chegaria a 'todas as nações' incluindo os moabitas."),
QuizQuestion(id:560,question:"O que Salomão ensina sobre a sabedoria em Provérbios 1:7?",options:["'O temor do Senhor é o princípio da","A sabedoria vem da educação","A sabedoria é inata","A sabedoria vem da experiência apenas"],correctIndex:0,explanation:"Provérbios 1:7: a sabedoria bíblica não começa com filosofia mas com o temor do Senhor — reconhecimento de Deus como Senhor e Criador orienta todo conhecimento.",reference:"Provérbios 1:7",category:.profetas,propheticMeaning:"'O temor do Senhor' não é pavor mas reverência que reorienta toda a existência para Deus — em Cristo, que é a Sabedoria de Deus (1 Co 1:30), o crente tem acesso à sabedoria divina pela fé e dependência."),
QuizQuestion(id:561,question:"O que Eclesiastes 12:13-14 conclui sobre o sentido da vida?",options:["A vida não tem sentido","'Teme a Deus e guarda os","A riqueza dá sentido","O prazer dá sentido"],correctIndex:1,explanation:"Eclesiastes conclui após investigar prazer, sabedoria e trabalho 'debaixo do sol': tudo é vaidade exceto temer a Deus e guardar mandamentos — a única sabedoria duradoura.",reference:"Eclesiastes 12:13-14",category:.profetas,propheticMeaning:"A 'vaidade' de tudo 'debaixo do sol' aponta para a necessidade de uma perspectiva 'acima do sol' — que Cristo oferece: vida eterna que transcende toda futilidade temporal (Jo 10:10)."),
QuizQuestion(id:562,question:"O que Isaías 55:8-9 diz sobre os pensamentos de Deus?",options:["Os pensamentos de Deus são iguais aos...","Os pensamentos de Deus são","'Meus pensamentos não são os vossos","Podemos entender plenamente Deus"],correctIndex:2,explanation:"Isaías 55:8-9: a transcendência divina — os caminhos e pensamentos de Deus superam infinitamente os humanos. Isso exige humildade intelectual e confiança soberana.",reference:"Isaías 55:8-9",category:.profetas,propheticMeaning:"A transcendência de Deus não é obstáculo à fé mas fundamento dela — confiamos em Deus precisamente porque ele vê o que não vemos, planeja o que não planejamos e pode o que não podemos."),
QuizQuestion(id:563,question:"O que Isaías 55:11 promete sobre a Palavra de Deus?",options:["A Palavra às vezes falha","A Palavra depende de quem a recebe para...","A Palavra funciona apenas em Israel","'A minha Palavra não voltará para mim"],correctIndex:3,explanation:"Isaías 55:11: a Palavra de Deus é eficaz por sua própria natureza — ela cumpre o propósito divino independentemente das circunstâncias aparentes.",reference:"Isaías 55:11",category:.profetas,propheticMeaning:"A promessa de Is 55:11 sustenta a pregação fiel — mesmo quando os resultados não aparecem, a Palavra está fazendo algo. Paulo planta, Apollos rega, mas Deus dá o crescimento (1 Co 3:6)."),
QuizQuestion(id:564,question:"O que Jeremias 17:9 diz sobre o coração humano?",options:["'Enganoso é o coração mais do que todas","O coração humano é bom por natureza","O coração humano é neutro","Apenas alguns corações são maus"],correctIndex:0,explanation:"Jr 17:9: o diagnóstico bíblico do coração humano — enganoso e corrupto. Esta é a razão pela qual a nova aliança (Jr 31:33) promete um coração novo.",reference:"Jeremias 17:9",category:.profetas,propheticMeaning:"O coração enganoso de Jeremias é a justificativa para a necessidade do novo nascimento de João 3 — nenhuma reforma exterior cura um coração radicalmente corrompido. Somente Deus pode dar coração novo."),
QuizQuestion(id:565,question:"O que o profeta Amós anuncia sobre a falsa adoração?",options:["Que qualquer adoração agrada a Deus","'Odeio, desprezo as vossas","Que os rituais bastam","Que a adoração é apenas pessoal"],correctIndex:1,explanation:"Amós 5:21-24: Deus rejeita festas, ofertas e cânticos de Israel que praticavam injustiça social. A adoração genuína produz justiça.",reference:"Amós 5:21-24",category:.profetas,propheticMeaning:"Amós 5:24 — 'corra o julgamento como água' — é citado por Martin Luther King em seus discursos. O profeta une adoração e justiça social de forma inseparável — o mesmo Deus que exige amor a ele exige amor ao próximo."),
QuizQuestion(id:566,question:"O que Miquéias 6:8 resume sobre a vida piedosa?",options:["Guardar todos os rituais","Oferecer muitos sacrifícios","'O que o Senhor pede de ti:","Construir templos"],correctIndex:2,explanation:"Miquéias 6:8 é uma das mais eloquentes sínteses da vida piedosa na Bíblia: justiça (ação correta), misericórdia (amor leal) e humildade com Deus — os três eixos da vida cristã.",reference:"Miquéias 6:8",category:.profetas,propheticMeaning:"Jesus resume igualmente: amor a Deus e ao próximo. Miquéias 6:8 mostra que a ética profética do AT antecipa o ensino de Cristo — 'a lei e os profetas' concentram-se nestes eixos (Mt 22:40)."),
QuizQuestion(id:567,question:"Quem foi Neemias e como ele orou antes de falar com o rei?",options:["Um profeta que nunca orou antes de agir","Um guerreiro que não precisava de oração","Um sacerdote do templo","Copeiro do rei persa que orou"],correctIndex:3,explanation:"Neemias 2:4-5: quando o rei perguntou o que queria, Neemias 'orou ao Deus do céu' instantaneamente antes de responder — modelo de oração em flash em situações urgentes.",reference:"Neemias 2:4-5",category:.profetas,propheticMeaning:"A oração rápida de Neemias antes de responder ao rei revela que a oração não precisa ser longa para ser real — é a dependência habitual de Deus que explode naturalmente nos momentos críticos."),
QuizQuestion(id:568,question:"O que foi o dilúvio e qual seu significado teológico?",options:["O julgamento divino sobre a maldade","Um mito sem significado","Um evento geológico apenas","Uma história simbólica apenas"],correctIndex:0,explanation:"Gênesis 6-9: o dilúvio representa o julgamento de Deus sobre o pecado e a graça preservando um remanescente fiel. 'Noé achou graça aos olhos do Senhor' (Gn 6:8).",reference:"Gênesis 6:8; 1 Pedro 3:20-21",category:.genesis,propheticMeaning:"Pedro usa o dilúvio como tipo do batismo (1 Pe 3:20-21) — as águas que julgaram o mundo foram as mesmas que sustentaram a arca; assim a água do batismo simboliza julgamento do velho eu e salvação do novo."),
QuizQuestion(id:569,question:"O que foi o chamado de Abraão e suas implicações?",options:["Um chamado para construir um templo","Deus chamou Abraão de Ur dos Caldeus:","Um chamado para ser rei de Israel","Um chamado para escrever as Escrituras"],correctIndex:1,explanation:"Gênesis 12:1-4: Abraão partiu 'sem saber para onde ia' (Hb 11:8) — a fé que obedece antes de entender, o modelo de toda fé bíblica.",reference:"Gênesis 12:1-4; Hebreus 11:8",category:.genesis,propheticMeaning:"Abraão partindo sem conhecer o destino é o paradigma da fé — não é fé que entende tudo antes de obedecer, mas obediência que confia no caráter de quem chama mesmo sem ver o mapa."),
QuizQuestion(id:570,question:"O que foi a aliança entre as metades (Gênesis 15)?",options:["Um rito de iniciação","Abraão e Deus passaram juntos","Deus sozinho passou entre os animais","Uma cerimônia de sacrifício normal"],correctIndex:2,explanation:"Gênesis 15:17: o forno fumegante e a tocha de fogo (Deus) passaram entre os animais divididos enquanto Abraão dormia — a aliança abraâmica é incondicional, mantida por Deus.",reference:"Gênesis 15:17-21",category:.genesis,propheticMeaning:"Deus sozinho passando entre os animais é extraordinário — normalmente ambas as partes passavam, assumindo a maldição do descumprimento. Deus assume unilateralmente toda a responsabilidade — tipo da nova aliança onde Cristo suporta a maldição por nós (Gl 3:13)."),
QuizQuestion(id:571,question:"Por que José foi vendido pelos irmãos?",options:["Por ser o mais velho","Por ter roubado de Jacó","Por ter se casado ilegalmente","Por inveja da bênção especial de"],correctIndex:3,explanation:"Gênesis 37: a inveja dos irmãos de José — ele era o favorito de Jacó e seus sonhos sugeriam superioridade. Os irmãos o venderam por 20 moedas de prata.",reference:"Gênesis 37:3-4,28",category:.genesis,propheticMeaning:"José vendido por prata (tipo de Judas vendendo Jesus) e descendo ao Egito (tipo da descida de Jesus à morte) para depois ser exaltado para salvar muitos — José é o tipo mais elaborado de Cristo no AT."),
QuizQuestion(id:572,question:"O que significa 'Emanuel' segundo Isaías 7:14?",options:["'Deus conosco'","Deus é grande","Deus é santo","Deus salva"],correctIndex:0,explanation:"Emanuel (Im-manu-el em hebraico) = 'Deus conosco.' Isaías 7:14 profetizou que uma virgem daria à luz um filho chamado Emanuel — cumprido em Jesus (Mt 1:23).",reference:"Isaías 7:14; Mateus 1:23",category:.profetas,propheticMeaning:"'Deus conosco' é o nome que encapsula toda a encarnação — o Eterno que habita nos céus desceu para habitar com os homens. Mateus 1:23 e 28:20 formam moldura: Emanuel (início) e 'estou convosco' (final)."),
QuizQuestion(id:573,question:"Qual profecia de Oséias 11:1 é usada em Mateus 2:15?",options:["'Do Egito chamei a virgem'","'Do Egito chamei o meu filho'","'Do Egito virei o Messias'","'Israel sairá do Egito no fim dos tempos'"],correctIndex:1,explanation:"Oséias 11:1: 'Do Egito chamei meu filho' — originalmente referindo-se ao Êxodo de Israel. Mateus 2:15 a aplica a Jesus retornando do Egito — Jesus como o verdadeiro Israel.",reference:"Oséias 11:1; Mateus 2:15",category:.profetas,propheticMeaning:"O uso de Oséias 11:1 por Mateus revela 'tipologia' — Jesus como o Israel verdadeiro que recapitula a história de Israel e a cumpre perfeitamente onde Israel falhou. Cristo é o Israel que Deus sempre pretendeu."),
QuizQuestion(id:574,question:"O que Isaías 7:14 especifica sobre o nascimento do Messias?",options:["Que nasceria em Belém","Que nasceria no inverno","Que uma virgem ('almah') conceberá e dará","Que nasceria durante o reinado de Davi"],correctIndex:2,explanation:"Isaías 7:14: 'almah' (jovem mulher/virgem) conceberá e dará à luz Emanuel. A Septuaginta traduziu 'almah' como 'parthenos' (virgem), confirmando o entendimento de nascimento virginal.",reference:"Isaías 7:14; Mateus 1:22-23",category:.profetas,propheticMeaning:"O debate 'almah' vs 'parthenos' é resolvido pelo cumprimento — qualquer que seja a tradução, Mateus vê o cumprimento em Maria. O nascimento virginal é a única forma de ter um ser totalmente humano e totalmente divino."),
QuizQuestion(id:575,question:"O que Isaías 40:22 diz sobre Deus e a criação?",options:["Deus criou um universo plano","Deus habita dentro da terra","A criação é uma ilusão","'O que está assentado sobre o"],correctIndex:3,explanation:"Isaías 40:22: a imagem de Deus 'assentado sobre o círculo da terra' e estendendo os céus revela sua transcendência sobre toda a criação — ele é mais do que ela.",reference:"Isaías 40:22",category:.profetas,propheticMeaning:"A transcendência de Deus sobre a criação ('os habitantes são como gafanhotos') garante que ele não está limitado pelas circunstâncias históricas ou naturais — pode intervir quando e como quiser."),
QuizQuestion(id:576,question:"O que Ezequiel 18:20 ensina sobre responsabilidade individual?",options:["'A alma que pecar","Os filhos pagam pelos pecados dos pais","A culpa é sempre coletiva","Deus pune gerações por pecados dos..."],correctIndex:0,explanation:"Ezequiel 18:20: responsabilidade individual — cada um responde pelos seus próprios pecados, não pelos de seus antepassados. Contexto de Israel questionando se estava sendo punido pelos pecados dos pais.",reference:"Ezequiel 18:20",category:.profetas,propheticMeaning:"A responsabilidade individual de Ezequiel 18 se cumpre em Cristo — ele não morreu pelo seus próprios pecados (não os tinha) mas pelos nossos, tornando possível a transferência de culpa pela fé."),
QuizQuestion(id:577,question:"O que o profeta Zacarias viu na visão do sacerdote Josué?",options:["O sacerdote adorando","Josué com roupas sujas (representando","O sacerdote recebendo riquezas","O sacerdote construindo o templo"],correctIndex:1,explanation:"Zacarias 3:1-5: Josué com roupas sujas sendo acusado pelo adversário; Deus repreende o acusador e substitui as roupas imundas por vestes festivas — imagem da justificação.",reference:"Zacarias 3:1-5",category:.profetas,propheticMeaning:"A visão de Zacarias 3 é a mais visual descrição da justificação no AT: o Satanás acusando com razão (roupas sujas = pecados reais), mas Deus intervindo soberanamente, removendo a culpa e vestindo com sua própria justiça."),
QuizQuestion(id:578,question:"Qual profecia de Isaías 52:13-53:12 é chamada de 'Quarto Cântico do Servo'?",options:["Um hino de vitória militar","Um poema sobre o exílio","O poema do Servo Sofredor que","Um cântico sobre o templo"],correctIndex:2,explanation:"O Quarto Cântico do Servo (Is 52:13-53:12) descreve: aparência desfigurada, rejeição, sofrimento vicário, morte, sepultura com ricos e ressurreição/prosperidade futura.",reference:"Isaías 52:13-53:12",category:.profetas,propheticMeaning:"Isaías 52:13 começa: 'Eis que o meu Servo prosperará' e termina em Is 53:12 com exaltação após a morte — a estrutura é: humilhação→sofrimento→morte→exaltação. O mesmo padrão de Fp 2:6-11 escrito 700 anos antes."),
QuizQuestion(id:579,question:"O que o livro de Daniel ensina sobre a soberania de Deus sobre os reinos humanos?",options:["Os reinos humanos são independentes","Deus não se importa com política","Apenas Israel está sob o domínio de Deus","'O Altíssimo tem domínio sobre o reino"],correctIndex:3,explanation:"Daniel 4:17,25,32: a lição que Nabucodonosor aprendeu da loucura — Deus soberanamente dá e remove poder humano. Este é o tema recorrente de Daniel.",reference:"Daniel 4:17,25",category:.profetas,propheticMeaning:"A soberania de Deus sobre todos os impérios (Babilônia, Pérsia, Grécia, Roma em Daniel) garante que o Rei dos reis está no controle da história — o mesmo Deus que governa Nabucodonosor governa os governantes de hoje."),
QuizQuestion(id:580,question:"O que Apocalipse 1:17-18 declara sobre Cristo glorificado?",options:["'Não temas; eu sou o primeiro e o último","Cristo continua sofrendo","Cristo está dormindo","Cristo voltou para o Pai permanentemente"],correctIndex:0,explanation:"Apocalipse 1:17-18: o Cristo glorificado se identifica como Alfa e Ômega, declara que esteve morto mas vive eternamente e possui as chaves da morte e do Hades.",reference:"Apocalipse 1:17-18",category:.geral,propheticMeaning:"'Tenho as chaves' — Cristo possui a autoridade sobre a morte (não o diabo, não o acaso). A ressurreição não apenas derrotou a morte mas colocou as chaves do domínio da morte nas mãos do Cristo ressurreto."),
QuizQuestion(id:581,question:"O que é o conceito de 'remanescente' nos profetas?",options:["A maioria de Israel que permaneceu fiel","O grupo minoritário fiel que Deus sempre","Todos os judeus que sobreviveram","Um grupo especial de sacerdotes"],correctIndex:1,explanation:"O 'remanescente' é o fio de continuidade divina através dos julgamentos — Elias pensou estar sozinho mas havia 7.000 (1 Rs 19:18); o remanescente retornou do exílio; Paulo vê o remanescente crente em Israel (Rm 11:5).",reference:"Isaías 10:21; Romanos 11:5",category:.profetas,propheticMeaning:"Paulo em Rm 11:5: 'assim também agora há um remanescente segundo a eleição da graça.' O conceito de remanescente garante que a fidelidade de Deus às suas promessas nunca depende da fidelidade da maioria."),
QuizQuestion(id:582,question:"O que é a 'nova criação' em 2 Coríntios 5:17?",options:["Uma nova tentativa de vida boa","Uma melhora gradual de caráter","'Se alguém está em Cristo","Uma realidade apenas futura"],correctIndex:2,explanation:"2 Co 5:17: 'nova criação' (ktisis) — o crente não é um velho ser humano reformado mas uma criação genuinamente nova, o início da nova criação que culminará em Apocalipse 21.",reference:"2 Coríntios 5:17",category:.geral,propheticMeaning:"A nova criação começa na conversão (2 Co 5:17) e se completará na nova criação cósmica (Ap 21:5). O crente é a 'primícia' da nova criação assim como Cristo é a primícia da ressurreição (1 Co 15:20)."),
QuizQuestion(id:583,question:"O que é 'redenção' segundo Paulo em Efésios 1:7?",options:["Uma segunda chance","A reforma do comportamento","Uma cerimônia religiosa","'Nele temos a redenção pelo seu"],correctIndex:3,explanation:"Ef 1:7: redenção (apolytrōsis) é libertação do cativeiro mediante pagamento de preço (lytrōn) — o sangue de Cristo é o preço que nos liberta do cativeiro do pecado.",reference:"Efésios 1:7",category:.geral,propheticMeaning:"O conceito de redenção no AT (go'el, Êxodo do Egito) encontra cumprimento supremo em Cristo — como o parente redentor Boaz e como Deus libertando Israel, Cristo nos liberta pagando o preço máximo: sua própria vida."),
QuizQuestion(id:584,question:"O que Paulo chama de 'adoção' em Romanos 8:15?",options:["'Recebestes o espírito de","Adotar crianças físicas","Um título eclesiástico","A conversão apenas"],correctIndex:0,explanation:"Rm 8:15: o Espírito de adoção (huiothesia) nos dá o direito e o privilégio de chamar Deus de 'Aba, Pai' — relação íntima de filho com Pai, antes impossível para pecadores.",reference:"Romanos 8:15; Gálatas 4:5-6",category:.geral,propheticMeaning:"'Aba' é o termo aramaico íntimo de criança para pai — Jesus usou-o em Getsêmani (Mc 14:36). O Espírito que habitava em Jesus e motivava esse clamor agora habita em nós e motiva o mesmo clamor filial."),
QuizQuestion(id:585,question:"O que Paulo chama de 'arras do Espírito'?",options:["Os dons espirituais","O Espírito Santo como...","A Ceia do Senhor","O batismo"],correctIndex:1,explanation:"Ef 1:13-14; 2 Co 1:22: o Espírito Santo é as 'arras' (arrabon — adiantamento, garantia, sinal de pagamento futuro) da herança eterna prometida.",reference:"Efésios 1:13-14; 2 Coríntios 1:22",category:.geral,propheticMeaning:"'Arras' no mundo comercial antigo era o depósito que garantia o contrato completo — o Espírito habitando em nós agora é o adiantamento da glória futura, garantindo que 'o que começou uma boa obra a completará' (Fp 1:6)."),
QuizQuestion(id:586,question:"O que Paulo diz sobre o sofrimento e a glória em 2 Coríntios 4:16-18?",options:["O sofrimento deve ser evitado","O sofrimento é punição","'O nosso homem exterior se corrompe","O sofrimento cancela as promessas de Deus"],correctIndex:2,explanation:"2 Co 4:16-18: a renovação interior paralela ao desgaste exterior, e a perspectiva eternas sobre as temporais — a visão do invisível transforma o sofrimento presente.",reference:"2 Coríntios 4:16-18",category:.geral,propheticMeaning:"'Fixando os olhos não nas coisas que se veem, mas nas que não se veem' — a vida cristã é orientada para o invisível eterno, não para o visível temporário. Essa reorientação não nega o sofrimento mas o transforma."),
QuizQuestion(id:587,question:"Qual é a importância de Gálatas 3:28 para a identidade cristã?",options:["Elimina diferenças físicas","Elimina todas as distinções culturais","É aplicável apenas à espiritualidade","'Não há judeu nem grego"],correctIndex:3,explanation:"Gl 3:28: a unidade em Cristo não elimina a diversidade (judeu permanece judeu, mulher permanece mulher) mas supera as hierarquias e barreiras que o pecado criou.",reference:"Gálatas 3:28",category:.geral,propheticMeaning:"Gl 3:28 é a aplicação de Gênesis 1:27 ('à imagem de Deus') ao novo mundo em Cristo — onde o pecado criou hierarquias e divisões, a graça restaura a unidade na diversidade da imagem divina."),
QuizQuestion(id:588,question:"O que Paulo diz sobre o corpo em 1 Coríntios 6:19-20?",options:["'O vosso corpo é o templo do Espírito","O corpo não tem importância espiritual","O corpo é prisão da alma","Apenas a alma importa para Deus"],correctIndex:0,explanation:"1 Co 6:19-20: o corpo do crente é templo do Espírito Santo — razão para honrar a Deus no corpo e evitar imoralidade sexual.",reference:"1 Coríntios 6:19-20",category:.geral,propheticMeaning:"O corpo como templo do Espírito é a revolução da encarnação estendida à Igreja — assim como Cristo habitou num corpo humano, o Espírito habita nos nossos corpos. O dualismo que despreza o corpo é antibíblico."),
QuizQuestion(id:589,question:"O que é o conceito de 'povo de Deus' ao longo da Bíblia?",options:["Apenas os judeus étnicos","Um povo chamado à aliança com Deus","Apenas a Igreja cristã","Apenas os que guardam a lei de Moisés"],correctIndex:1,explanation:"O 'povo de Deus' é continuidade histórica: Israel no AT, Igreja no NT, culminando na grande multidão de Ap 7:9 — todos os que respondem ao chamado de Deus pela fé.",reference:"1 Pedro 2:9-10; Romanos 9:25-26",category:.geral,propheticMeaning:"Pedro citando Oséias 2:23 para a Igreja gentílica (1 Pe 2:10) mostra que 'os que não eram povo' se tornaram 'povo de Deus' — a promessa a Israel expandiu-se à Igreja universal em Cristo."),
QuizQuestion(id:590,question:"O que é a 'santidade' de Deus em Isaías 6?",options:["A bondade de Deus apenas","A onipotência de Deus","A transcendência absoluta de Deus","A presença de Deus em todos os lugares"],correctIndex:2,explanation:"Isaías 6: a visão do Senhor exaltado fez os serafins proclamar 'Santo, Santo, Santo' e Isaías exclamar 'Ai de mim! sou desfeito.' A santidade de Deus revela a pecaminosidade humana.",reference:"Isaías 6:1-8",category:.profetas,propheticMeaning:"A visão da santidade de Deus em Isaías 6 é a experiência formativa do profeta — sem a visão de quem Deus é, não há senso real do pecado. O evangelho começa com a santidade de Deus, não com nossa bondade."),
QuizQuestion(id:591,question:"Quem é o 'Espírito de adoção' em Romanos 8:15?",options:["Um espírito angelical","O espírito humano renovado","Um sentimento de paz interior","O Espírito Santo que habita no"],correctIndex:3,explanation:"Rm 8:15: o próprio Espírito Santo de Deus habita no crente, gerando e confirmando a filiação — o clamor 'Aba, Pai' é evidência do Espírito operando dentro.",reference:"Romanos 8:15; Gálatas 4:6",category:.geral,propheticMeaning:"Gálatas 4:6: 'Deus enviou o Espírito de seu Filho aos nossos corações, clamando: Aba, Pai.' O mesmo Espírito que estava em Jesus, fazendo-o chamar Deus de Pai, agora está em nós, nos dando o mesmo acesso filial."),
QuizQuestion(id:592,question:"O que Paulo chama de 'glória de Deus' em Romanos 3:23?",options:["O padrão de excelência e","Os milagres de Deus","A beleza do universo","Os benefícios de ser cristão"],correctIndex:0,explanation:"Rm 3:23: 'todos pecaram e carecem da glória de Deus' — a glória como o padrão de perfeição divina que o ser humano deveria refletir mas perdeu pelo pecado.",reference:"Romanos 3:23",category:.geral,propheticMeaning:"A 'perda da glória' em Rm 3:23 explica o propósito da salvação: '2 Co 3:18 — sendo transformados de glória em glória' é a restauração da imagem de Deus perdida em Adão, renovada em Cristo."),
QuizQuestion(id:593,question:"Qual é a diferença entre o 'homem velho' e o 'homem novo' em Paulo?",options:["Jovem e velho fisicamente","O 'homem velho' é a natureza","Um cristão e um não-cristão","A carne e o espírito"],correctIndex:1,explanation:"Ef 4:22-24; Cl 3:9-10: 'depondes o velho homem' e 'revestes o novo' — não uma realidade automática mas uma exortação a viver a partir da nova identidade em Cristo.",reference:"Efésios 4:22-24",category:.geral,propheticMeaning:"O 'novo homem' de Ef 4:24 é 'criado segundo Deus em justiça e santidade' — restauração da imagem divina perdida em Adão (Gn 1:27). Cristo é o 'último Adão' (1 Co 15:45) que inaugurou a humanidade nova."),
QuizQuestion(id:594,question:"O que é o 'dom perfeito' que vem de cima em Tiago 1:17?",options:["A prosperidade material","Os dons espirituais apenas","'Toda boa dádiva e todo dom","A saúde e a força"],correctIndex:2,explanation:"Tiago 1:17: toda dádiva boa vem de Deus — do Pai imutável ('sem mudança nem sombra de variação') que é oposto às divindades caprichosas do paganismo.",reference:"Tiago 1:17",category:.geral,propheticMeaning:"A imutabilidade de Deus (Pai das luzes sem variação) é fundamento da confiança — ao contrário dos astros que movem e eclipsam, Deus é sempre o mesmo, tornando suas promessas absolutamente confiáveis."),
QuizQuestion(id:595,question:"O que João 10:10 diz sobre o propósito de Cristo?",options:["Que veio estabelecer uma religião","Que veio para ensinar apenas","Que veio para julgamento somente","'O ladrão vem somente para roubar"],correctIndex:3,explanation:"Jo 10:10: o contraste entre o ladrão (Satanás, falsos pastores) e o bom pastor — Jesus veio dar 'vida em abundância' (zōēn perissos), não meramente existência mas vida em pleno florescimento.",reference:"João 10:10",category:.geral,propheticMeaning:"'Vida em abundância' não é garantia de prosperidade material, mas a vida divina do Filho derramada no crente — comunhão com Deus, paz que excede o entendimento, e amor inextinguível que flui do próprio Deus."),
QuizQuestion(id:596,question:"O que é o 'reino de Deus' vs o 'reino dos céus' no NT?",options:["O mesmo reino com terminologia","Dois reinos diferentes","Um reino presente e um futuro","O reino na terra e no céu"],correctIndex:0,explanation:"'Reino de Deus' e 'reino dos céus' são equivalentes — Mateus evita o Nome 'Deus' por reverência judaica ao tetragrama, usando 'céus' como circunlóquio divino.",reference:"Mateus 4:17; Marcos 1:15",category:.geral,propheticMeaning:"O reino anunciado por Jesus não é meramente futuro nem apenas espiritual — 'o reino de Deus está no meio de vós' (Lc 17:21). Tem dimensão presente (já veio em Cristo) e futura (virá em plenitude)."),
QuizQuestion(id:597,question:"O que Paulo diz sobre a intercessão de Cristo em Romanos 8:34?",options:["Cristo cessou de interceder após a...","'Cristo Jesus... que também intercede por...","A intercessão é apenas humana","Cristo intercede apenas pelos apóstolos"],correctIndex:1,explanation:"Rm 8:34: dupla segurança — Cristo morreu, ressuscitou, está à direita de Deus E intercede por nós. Nenhuma condenação pode prevalecer (v.33-34).",reference:"Romanos 8:34",category:.geral,propheticMeaning:"Cristo intercedendo permanentemente (Hb 7:25) garante a segurança eterna do crente — o próprio acusador (Satanás) é derrotado pelo Intercessor que está à direita do Pai juiz."),
QuizQuestion(id:598,question:"O que significa 'santificado' em João 17:17?",options:["Tornar-se perfeito instantaneamente","Um ritual de limpeza física","'Santifica-os na tua verdade","Ser separado fisicamente do mundo"],correctIndex:2,explanation:"João 17:17: a oração sacerdotal de Jesus pede a santificação dos discípulos pela Palavra — ser 'separado para Deus' pelo processo de transformação que a verdade opera.",reference:"João 17:17",category:.geral,propheticMeaning:"'Santifica-os na tua verdade' mostra que a santificação é obra de Deus operada por sua Palavra — não autoesforço mas abertura à Palavra que o Espírito usa para transformar o crente progressivamente."),
QuizQuestion(id:599,question:"O que o apóstolo João ensina sobre o amor como prova de vida espiritual?",options:["O amor não é prova de nada","O amor é apenas sentimento","Apenas crentes com dons espirituais amam","'Sabemos que passamos da morte para a vida"],correctIndex:3,explanation:"1 João 3:14: o amor aos irmãos é a evidência tangível da vida espiritual — quem foi transformado por Cristo naturalmente ama os outros em quem Cristo habita.",reference:"1 João 3:14",category:.geral,propheticMeaning:"O amor fraterno como prova da vida espiritual é a lógica de 1 João 4:20-21: quem diz amar a Deus mas odeia o irmão mente — pois não pode amar o Deus invisível quem odeia o irmão visível."),
QuizQuestion(id:600,question:"O que é o dom da profecia segundo 1 Coríntios 14:3?",options:["'Aquele que profetiza fala aos","Predizer o futuro apenas","O dom de ensinar apenas","Falar em línguas traduzidas"],correctIndex:0,explanation:"1 Co 14:3: a profecia em contexto de adoração serve para 'edificação, exortação e consolação' — o critério primário é edificar a Igreja, não impressionar.",reference:"1 Coríntios 14:3",category:.geral,propheticMeaning:"Paulo valorizando a profecia acima das línguas (1 Co 14:1-5) porque edifica a Igreja revela o princípio: os dons do Espírito devem ser avaliados pelo critério do amor (1 Co 13) e da edificação da comunidade."),
QuizQuestion(id:601,question:"O que ensina o Salmo 139 sobre o conhecimento de Deus acerca de nós?",options:["Deus nos conhece apenas superficialmente","'Senhor, tu me sondaste e me","Deus nos conhece apenas coletivamente","Deus conhece apenas nossos pecados"],correctIndex:1,explanation:"Salmo 139: Deus conhece cada pensamento antes de ser articulado, cada lugar onde estamos, cada momento de nossa formação no ventre — conhecimento total e íntimo.",reference:"Salmos 139:1-4",category:.geral,propheticMeaning:"O Salmo 139 é ao mesmo tempo assustador (não há como esconder de Deus) e consolador (o Criador que me formou no ventre me conhece completamente e ainda assim me ama). É o fundamento da intimidade na oração."),
QuizQuestion(id:602,question:"O que o Salmo 139:13-14 diz sobre a formação humana?",options:["A vida começa ao nascer","A ciência define o início da vida","'Tu formaste os meus rins","O ser humano se faz a si mesmo"],correctIndex:2,explanation:"Salmo 139:13-14: Deus está ativamente formando o ser humano no ventre — fundamento bíblico para a sacralidade da vida desde a concepção.",reference:"Salmos 139:13-16",category:.geral,propheticMeaning:"A formação divina no ventre (Sl 139:13; Jr 1:5; Lc 1:44) aponta para a sacralidade da vida pré-natal. João Batista 'saltou de alegria' no ventre ao presença de Maria — mostrando consciência e resposta no útero."),
QuizQuestion(id:603,question:"Qual é o tema do Salmo 1?",options:["A criação do mundo","O sofrimento de Israel","A queda de Sião","O contraste entre o justo"],correctIndex:3,explanation:"Salmo 1: o homem bem-aventurado evita os caminhos dos ímpios e medita na lei do Senhor — como árvore plantada junto às correntes das águas. Os ímpios são como palha dispersada pelo vento.",reference:"Salmos 1:1-6",category:.geral,propheticMeaning:"O Salmo 1 abre o saltério com dois caminhos e dois destinos — o 'caminho dos justos' e o 'caminho dos ímpios.' Jesus retoma isso no Sermão do Monte com a 'porta estreita e larga' (Mt 7:13-14)."),
QuizQuestion(id:604,question:"Qual é o Salmo de louvor que começa 'Louvai ao Senhor, invocai o seu nome'?",options:["Salmo 105","Salmo 23","Salmo 119","Salmo 150"],correctIndex:0,explanation:"O Salmo 105 começa: 'Louvai ao Senhor, invocai o seu nome, fazei conhecidos entre os povos os seus feitos' — hino que reconta a história de Israel como história das maravilhas de Deus.",reference:"Salmos 105:1",category:.geral,propheticMeaning:"Recontar a história das obras de Deus (Sl 105; 106; 136) é a base do louvor bíblico — adoração que conhece quem Deus é pelo que ele fez. A memória das obras de Deus gera fé para novas obras."),
QuizQuestion(id:605,question:"O que o Salmo 103 diz sobre o caráter de Deus?",options:["Que Deus está distante","'Misericordioso e compassivo é o...","Que Deus pune sem misericórdia","Que Deus apenas abençoa os perfeitos"],correctIndex:1,explanation:"Salmo 103: um dos mais belos textos sobre o caráter de Deus — perdoa todas as iniquidades, sara todas as doenças, afasta as transgressões como oriente do ocidente, e sua misericórdia dura para sempre.",reference:"Salmos 103:3,12",category:.geral,propheticMeaning:"'Como dista o oriente do ocidente' (Sl 103:12) descreve o perdão divino espacialmente — infinito, sem limites. Isso encontra cumprimento em Cristo: 'a quem Deus propôs como propiciação, pelo sangue' (Rm 3:25)."),
QuizQuestion(id:606,question:"Qual é a promessa do Salmo 34:18?",options:["'Deus protege os fortes'","'Deus abençoa os ricos'","'O Senhor está perto dos que têm o...","'O Senhor responde apenas aos perfeitos'"],correctIndex:2,explanation:"Salmo 34:18: Deus está particularmente perto dos que têm o coração partido e o espírito abatido — as aparentes fraquezas são as que mais atraem a presença especial de Deus.",reference:"Salmos 34:18",category:.geral,propheticMeaning:"A promessa ao quebrantado cumpre a bem-aventurança dos que choram (Mt 5:4) — não é a força mas a fraqueza reconhecida que se torna o lugar de encontro com a força de Deus."),
QuizQuestion(id:607,question:"O que o Salmo 37:4 promete?",options:["'Busca riqueza e receberás'","'Ore muito e receberás'","'Seja bom e receberás bênçãos'","'Deleita-te também no Senhor"],correctIndex:3,explanation:"Salmo 37:4: deleitando-se em Deus, os desejos do coração são transformados — passamos a desejar o que Deus quer dar, não apenas o que queremos naturalmente.",reference:"Salmos 37:4",category:.geral,propheticMeaning:"'Deleitando-te em Deus' é a condição — não a fórmula mágica para receber o que queremos, mas a transformação que faz querermos o que Deus quer. O desejo do coração transformado coincide com a vontade de Deus."),
QuizQuestion(id:608,question:"O que o Salmo 51 exprime sobre arrependimento?",options:["A oração de Davi após seu pecado com...","Que o pecado não precisa de arrependimento","Que o arrependimento é apenas externo","Que Deus ignora os pecados do rei"],correctIndex:0,explanation:"Salmo 51: o modelo bíblico de arrependimento genuíno — reconhecimento do pecado, apelo à misericórdia de Deus, pedido de coração novo e Espírito renovado.",reference:"Salmos 51:1-2,10",category:.geral,propheticMeaning:"'Cria em mim um coração puro' (bara — palavra usada apenas para criação divina) — Davi sabia que arrependimento verdadeiro exige criação nova, não mero esforço humano. É a antecipação do 'coração novo' de Ezequiel 36."),
QuizQuestion(id:609,question:"O que é a 'grande comissão' segundo os quatro Evangelhos?",options:["Uma única versão da mesma missão","Cada evangelho tem sua ênfase: Mateus","Apenas o que Mateus registrou","Uma missão apenas para os apóstolos"],correctIndex:1,explanation:"A comissão missionária aparece em Mateus 28:18-20, Marcos 16:15, Lucas 24:46-49 e João 20:21-22 — cada evangelho enfatizando aspectos complementares da missão da Igreja.",reference:"Mateus 28:18-20; Lucas 24:47-49",category:.geral,propheticMeaning:"Os quatro registros da comissão mostram a missão como multifacetada — discipular, proclamar, testemunhar e enviar são aspectos inseparáveis de uma mesma missão orientada pelo Espírito."),
QuizQuestion(id:610,question:"O que Paulo ensina sobre a Igreja como 'família de Deus' em Efésios 2:19?",options:["Apenas uma metáfora sem implicações","A Igreja é apenas uma organização","'Já não sois estrangeiros","A família de Deus é apenas a Israel étnico"],correctIndex:2,explanation:"Ef 2:19: os gentios que eram 'estrangeiros' tornaram-se 'membros da família de Deus' — cidadania celestial e parentesco divino simultaneamente.",reference:"Efésios 2:19-22",category:.geral,propheticMeaning:"A Igreja como 'família de Deus' tem implicações práticas: responsabilidade mútua, recursos compartilhados, cuidado mútuo — não apenas comunidade espiritual abstrata mas parentesco concreto que forma o 'novo Israel' em Cristo."),
QuizQuestion(id:611,question:"O que é o 'sacerdócio de Melquisedeque' em Hebreus 7?",options:["Uma ordem sacerdotal desaparecida","Um sacerdócio apenas para judeus","O sacerdócio papal","Um sacerdócio superior ao levítico: sem"],correctIndex:3,explanation:"Hebreus 7: Melquisedeque como rei-sacerdote de Salém sem genealogia registrada é tipo perfeito do sacerdócio eterno de Cristo — sacerdote para sempre, não por linhagem mas por vida indissolúvel (v.16).",reference:"Hebreus 7:15-17",category:.geral,propheticMeaning:"Cristo como 'sacerdote para sempre segundo a ordem de Melquisedeque' (Sl 110:4) superou o sacerdócio levítico perecível — sua intercessão é eterna, seu sacrifício foi único e seu acesso ao Pai é permanente."),
QuizQuestion(id:612,question:"O que Paulo diz sobre a oração sem cessar em 1 Tessalonicenses 5:17?",options:["Viver numa atitude constante de...","Orar 24 horas por dia literalmente","Rezar fórmulas repetidas","A oração não tem horários"],correctIndex:0,explanation:"1 Ts 5:17: 'orai sem cessar' é um estilo de vida, não uma obrigação de rezar literalmente cada minuto — uma orientação do coração que mantém comunicação aberta com Deus.",reference:"1 Tessalonicenses 5:17",category:.geral,propheticMeaning:"A oração contínua é possibilitada pelo Espírito que 'geme por nós' (Rm 8:26) — não depende apenas do nosso esforço mas da obra do Espírito que mantém o canal de comunicação com o Pai mesmo nos momentos de fraqueza."),
QuizQuestion(id:613,question:"O que é a 'tribulação' mencionada nas cartas de Paulo?",options:["Apenas perseguição religiosa","Thlipsis","Um período específico do fim dos tempos","Uma maldição que pode ser evitada pela fé"],correctIndex:1,explanation:"Thlipsis (tribulação, pressão) é a experiência normal do cristão no mundo — Paulo diz que 'todos que quiserem viver piedosamente em Cristo Jesus serão perseguidos' (2 Tm 3:12).",reference:"Atos 14:22; Romanos 5:3",category:.geral,propheticMeaning:"A tribulação produz perseverança→caráter→esperança (Rm 5:3-5) — não é obstáculo ao crescimento espiritual mas seu meio. A teologia que promete vida sem tribulação contradiz o NT consistentemente."),
QuizQuestion(id:614,question:"O que Paulo ensina sobre a 'morte ao pecado' em Romanos 6?",options:["O pecado não existe mais para o crente","O pecado é impossível após a conversão","O crente morreu ao domínio do pecado com...","Apenas apóstolos morreram ao pecado"],correctIndex:2,explanation:"Romanos 6: a morte ao pecado é posicional (já aconteceu na cruz com Cristo) e deve ser aplicada praticamente (considerai-vos mortos para o pecado — v.11).",reference:"Romanos 6:6,11",category:.geral,propheticMeaning:"O 'considerar-se' (logizesthe) de Rm 6:11 é a aplicação da identidade: o crente é morto ao pecado na posição (justificação) mas precisa afirmar isso na prática (santificação). A identidade precede a ética."),
QuizQuestion(id:615,question:"O que é a 'transformação pela contemplação' em 2 Coríntios 3:18?",options:["Meditação mística","Contemplação sem ação","Um processo apenas espiritual","'Refletindo como num espelho a"],correctIndex:3,explanation:"2 Co 3:18: o crente que contempla a glória de Cristo na Palavra é transformado progressivamente à imagem de Cristo pelo Espírito Santo.",reference:"2 Coríntios 3:18",category:.geral,propheticMeaning:"A transformação 'de glória em glória' é o mecanismo da santificação: foco em Cristo (não esforço próprio) produz semelhança a Cristo. O Espírito usa a contemplação da Palavra para reproduzir o caráter do Filho."),
QuizQuestion(id:616,question:"O que Paulo chama de 'poder do evangelho' em Romanos 1:16?",options:["'Não me envergonho do evangelho","Poder físico de curar","Poder político de mudar leis","Poder econômico de enriquecer"],correctIndex:0,explanation:"Rm 1:16: o evangelho não é apenas informação mas dunamis (poder dinâmico) de Deus que opera salvação — eficaz para judeus e gentios sem distinção.",reference:"Romanos 1:16",category:.geral,propheticMeaning:"'Dunamis' (de onde vem 'dinâmica') — o evangelho é ativo, não passivo; transforma, não apenas informa. Paulo não se envergonha do que parece loucura (1 Co 1:18) porque experimenta seu poder transformador."),
QuizQuestion(id:617,question:"O que é o 'justo que vive pela fé' em Habacuque e Paulo?",options:["O justo que pratica rituais religiosos","O crente que orienta toda a vida pela...","O justo que obedece perfeitamente a lei","O justo que tem visões e sonhos"],correctIndex:1,explanation:"'O justo viverá pela sua fé' (Hc 2:4) é citado três vezes no NT — em Romanos (a fé que justifica), Gálatas (a fé que liberta da lei) e Hebreus (a fé que persevera).",reference:"Habacuque 2:4; Romanos 1:17; Gálatas 3:11",category:.geral,propheticMeaning:"A tripla citação de Hc 2:4 no NT revela que é a pedra angular da soteriologia: Romanos enfatiza 'o justo' (quem?), Gálatas enfatiza 'pela fé' (como?) e Hebreus enfatiza 'viverá' (para que?)."),
QuizQuestion(id:618,question:"O que João ensina sobre a verdade que liberta em João 8:32?",options:["Qualquer verdade liberta","A educação liberta","'Conhecereis a verdade e a","A filosofia liberta"],correctIndex:2,explanation:"João 8:32-36: a 'verdade' que liberta é a pessoa de Cristo ('Eu sou a verdade' — Jo 14:6) e seu ensino. A liberdade genuína é libertação da escravidão ao pecado (v.34).",reference:"João 8:32,36",category:.geral,propheticMeaning:"'Se o Filho vos libertar, sereis verdadeiramente livres' (Jo 8:36) — a liberdade mais profunda não é política ou intelectual mas ontológica: libertação do domínio do pecado que escraviza a vontade humana."),
QuizQuestion(id:619,question:"O que Paulo ensina sobre enganar a nós mesmos em 1 Coríntios 3:18?",options:["Nunca nos enganamos","A sabedoria mundana e a divina são","Apenas os eruditos enganam-se","'Se alguém dentre vós se imagina sábio"],correctIndex:3,explanation:"1 Co 3:18-20: a sabedoria de Deus inverte a sabedoria humana — o que o mundo chama de loucura (a cruz) é o poder e a sabedoria de Deus; o que o mundo chama de sabedoria é loucura para Deus.",reference:"1 Coríntios 3:18-20",category:.geral,propheticMeaning:"A inversão de sabedoria em 1 Co 1-3 é um dos temas mais revolucionários de Paulo — o crucificado como sabedoria de Deus subverte toda hierarquia intelectual e social, tornando o evangelho acessível a todos."),
QuizQuestion(id:620,question:"O que Tiago 4:13-15 diz sobre o planejamento?",options:["'Se o Senhor quiser e nós vivermos","Planeje tudo sem consultar Deus","Não faça planos","Planejamento é falta de fé"],correctIndex:0,explanation:"Tiago 4:13-15: o orgulho de quem planeja sem reconhecer a soberania de Deus é vaidade — a frase cristã 'se Deus quiser' (deo volente, DV) reflete humildade diante da soberania divina.",reference:"Tiago 4:13-15",category:.geral,propheticMeaning:"Planejar com 'se o Senhor quiser' não é fatalismo mas fé — reconhecimento de que Deus é o Senhor da história, não nós. Provérbios 16:9: 'O coração do homem planeja o seu caminho, mas o Senhor dirige os seus passos.'"),
QuizQuestion(id:621,question:"O que Paulo ensina sobre dar graças em tudo (1 Tessalonicenses 5:18)?",options:["Agradeça apenas pelas coisas boas","'Em tudo dai graças","A gratidão é apenas para pastores","Agradeça apenas depois de orar"],correctIndex:1,explanation:"1 Ts 5:18: 'em tudo' (en panti) não é 'por tudo' — não agradecemos pelo mal em si, mas em toda situação mantemos uma atitude grata porque Deus é soberano e fiel.",reference:"1 Tessalonicenses 5:18",category:.geral,propheticMeaning:"A gratidão 'em tudo' requer a perspectiva de Romanos 8:28 — quando sabemos que 'todas as coisas contribuem para o bem', podemos ser gratos mesmo no sofrimento, sem fingir que o sofrimento é bom."),
QuizQuestion(id:622,question:"O que é a 'corrida da fé' em Hebreus 12:1?",options:["Uma corrida física como esporte","Uma competição entre cristãos","A vida cristã comparada a uma","Apenas para atletas"],correctIndex:2,explanation:"Hb 12:1-2: a corrida da fé exige: 1) lançar fora o peso (excesso) e o pecado (obstáculo), 2) perseverança (hypomonē — suportar), 3) olhos em Jesus. Os 'heróis' de Hb 11 são os espectadores.",reference:"Hebreus 12:1-2",category:.geral,propheticMeaning:"Jesus como 'autor e consumador da fé' significa que ele não apenas modelou a fé mas é a fonte e o fim dela — a corrida começa em Cristo (fé) e termina em Cristo (visão). Ele é tanto o caminho quanto o destino."),
QuizQuestion(id:623,question:"O que é a 'aliança do arco-íris' com Noé e seu alcance?",options:["Uma aliança apenas com Israel","Uma aliança apenas espiritual","Uma aliança que expirou","A aliança de Deus com Noé"],correctIndex:3,explanation:"Gênesis 9:9-17: a aliança de Noé é a mais abrangente — inclui Noé, seus descendentes e toda criatura viva. É incondicional e eterna, com o arco-íris como sinal.",reference:"Gênesis 9:9-17",category:.genesis,propheticMeaning:"A aliança de Noé demonstra que Deus cuida não apenas de Israel ou da Igreja, mas de toda a criação — fundamento teológico do cuidado cristão com o meio ambiente e da crença numa nova criação (Ap 21:5)."),
QuizQuestion(id:624,question:"O que é a 'aliança mosaica' e qual foi sua função?",options:["A aliança do Sinai com Israel mediada","A aliança que salva","Uma aliança eterna e suficiente","A aliança mais importante da Bíblia"],correctIndex:0,explanation:"A aliança mosaica (Êx 19-24) foi um pacto condicional entre Deus e Israel — bênçãos pela obediência, maldições pela desobediência (Dt 28). Paulo a chama de 'pedagogo para Cristo' (Gl 3:24).",reference:"Êxodo 19:5-6; Gálatas 3:24",category:.profetas,propheticMeaning:"A função da aliança mosaica era revelar o pecado (Rm 3:20) e demonstrar a impossibilidade humana de cumprir a lei — preparando Israel e a humanidade para o Mediador da Nova Aliança: Jesus Cristo."),
QuizQuestion(id:625,question:"O que é a 'Grande Tribulação' em Mateus 24:21?",options:["Um período de sofrimento espiritual apenas","'Porque haverá então grande tribulação","Um período já passado completamente","A perseguição romana no séc. I apenas"],correctIndex:1,explanation:"Mateus 24:21: Jesus anunciou uma tribulação sem precedentes, que a maioria dos intérpretes localiza no fim dos tempos, com aplicação parcial na destruição de Jerusalém em 70 d.C.",reference:"Mateus 24:21; Daniel 12:1",category:.geral,propheticMeaning:"A Grande Tribulação de Mt 24:21 ecoa Daniel 12:1: 'haverá tempo de angústia como nunca houve desde que houve nação.' A promessa é que 'quem perseverar até o fim será salvo' (Mt 24:13)."),
QuizQuestion(id:626,question:"O que Paulo ensina sobre a 'nova criação' em Gálatas 6:15?",options:["Que obras religiosas importam","Que rituais são suficientes","'Nem a circuncisão nem a","Que a lei é o que importa"],correctIndex:2,explanation:"Gl 6:15: ao final da carta sobre a liberdade da lei, Paulo declara que a nova criação (não a circuncisão nem incircuncisão) é o que importa — a transformação real supera qualquer marca religiosa.",reference:"Gálatas 6:15",category:.geral,propheticMeaning:"'Nova criação' (kainos ktisis) encapsula todo o argumento de Gálatas: a salvação não é reforma do velho (lei + obras) mas criação nova em Cristo. A circuncisão do coração (Dt 30:6; Rm 2:29) é o que importa."),
QuizQuestion(id:627,question:"O que Hebreus 11 chama de 'herança da fé'?",options:["Bênçãos materiais dos antepassados","As Escrituras","A traição de Judas","O registro dos heróis da fé do AT que..."],correctIndex:3,explanation:"Hebreus 11:39-40: os heróis da fé do AT receberam bom testemunho mas não a promessa — 'Deus havia reservado algo melhor para nós, para que eles não chegassem à perfeição sem nós.'",reference:"Hebreus 11:39-40",category:.geral,propheticMeaning:"Os heróis do AT aguardavam Cristo sem vê-lo; nós aguardamos a consumação sabendo que Cristo já veio. Somos 'mais abençoados' (Mt 13:16-17) mas a mesma fé nos une através dos séculos."),
QuizQuestion(id:628,question:"O que é 'regeneração' segundo Tito 3:5 e João 3?",options:["A obra sobrenatural de Deus no coração","Uma segunda chance","Um processo gradual sem começo definido","Uma decisão humana de melhorar"],correctIndex:0,explanation:"Regeneração (palingenesia em Tito 3:5; gennēthēnai anōthen em Jo 3:3) é a obra criativa do Espírito que dá vida espiritual — antes impossível ao homem morto em pecado (Ef 2:1-5).",reference:"João 3:5-8; Tito 3:5",category:.geral,propheticMeaning:"A regeneração precede a fé (pois o morto não pode crer) — Deus age primeiro, dando vida (Ez 36:26-27), e o regenerado crê. Isso garante que a salvação é de Deus de ponta a ponta, 'para que ninguém se glorie' (Ef 2:9)."),
QuizQuestion(id:629,question:"O que é o 'selo do Espírito' em Efésios 1:13-14?",options:["Uma marca física","Os crentes foram selados pelo Espírito","Um dom especial dos apóstolos","Uma experiência posterior à conversão"],correctIndex:1,explanation:"Ef 1:13-14: ao crer, os efésios foram 'selados pelo Espírito Santo da promessa' — o selo indica propriedade (pertencemos a Deus), autenticidade (somos genuínos) e segurança (protegidos até o dia da redenção).",reference:"Efésios 1:13-14",category:.geral,propheticMeaning:"O 'selo do Espírito' (2 Co 1:22) é a garantia divina da salvação — não depende de nossos sentimentos ou obras mas da promessa imutável de Deus que selou os seus. O dia da redenção plena é certo."),
QuizQuestion(id:630,question:"O que Paulo ensina sobre a 'consciência' do crente em 1 Coríntios 8?",options:["Ignore a consciência dos outros","A consciência é irrelevante para cristãos","A consciência é educável pela Palavra","Apenas faça o que a consciência manda sem"],correctIndex:2,explanation:"1 Co 8: Paulo instrui sobre alimentos sacrificados a ídolos — o 'forte' (com conhecimento) pode comer, mas deve considerar a consciência do 'fraco'. O amor é o árbitro da liberdade cristã.",reference:"1 Coríntios 8:9-13",category:.geral,propheticMeaning:"'Quando assim pecais contra os irmãos... pecais contra Cristo' (1 Co 8:12) — fazer um irmão fraco tropeçar não é apenas questão ética mas ferida em Cristo que o amou o suficiente para morrer por ele."),
]
